import { BREAK, CONTINUE, RETURN, AWAIT } from '../share/const'
import { hoist, pattern, ForXHandler } from './helper'
import { getAsyncIterator } from '../share/util'
import * as estree from 'estree'
import Scope from '../scope'
import evaluate from '.'

export function ExpressionStatement(node: estree.ExpressionStatement, scope: Scope) {
  evaluate(node.expression, scope)
}

export interface BlockOptions {
  invasived?: boolean
  hoisted?: boolean
}

export function BlockStatement(
  block: estree.BlockStatement,
  scope: Scope,
  options: BlockOptions = {},
) {
  const {
    invasived = false,
    hoisted = false,
  } = options

  const subScope = invasived ? scope : new Scope(scope)

  if (!hoisted) {
    hoist(block, subScope, { onlyBlock: true })
  }

  for (let i = 0; i < block.body.length; i++) {
    const result = evaluate(block.body[i], subScope)
    if (result === BREAK || result === CONTINUE || result === RETURN) {
      return result
    }
  }
}

export function EmptyStatement(): any {
  // No operation here
}

export function DebuggerStatement(): any {
  debugger
}

export function ReturnStatement(node: estree.ReturnStatement, scope: Scope) {
  RETURN.RES = node.argument ? (evaluate(node.argument, scope)) : undefined
  return RETURN
}

export function BreakStatement(node: estree.BreakStatement) {
  if (node.label) {
    BREAK.LABEL = node.label.name
  } else {
    delete BREAK.LABEL
  }
  return BREAK
}

export function ContinueStatement(node: estree.ContinueStatement) {
  if (node.label) {
    CONTINUE.LABEL = node.label.name
  } else {
    delete CONTINUE.LABEL
  }
  return CONTINUE
}

export function WithStatement(node: estree.WithStatement, scope: Scope) {
  // WithStatement extends the scope chain with the object
  // Note: This is deprecated and not allowed in strict mode
  const obj = evaluate(node.object, scope)
  
  // Create a new scope with the object's properties
  const withScope = new Scope(scope)
  
  // Add all enumerable properties from the object to the scope
  if (obj && typeof obj === 'object') {
    for (const key in obj) {
      withScope.var(key, obj[key])
    }
  }
  
  return evaluate(node.body, withScope)
}

export function LabeledStatement(node: estree.LabeledStatement, scope: Scope) {
  const label = node.label.name
  
  // Store the current label in a special scope variable
  // Use a NON-isolated scope so the direct child can access it
  const labelScope = new Scope(scope, false)
  labelScope.let('__LABEL__', label)
  
  const result = evaluate(node.body, labelScope)
  
  // Check if this is a break targeting this label
  if (result === BREAK && BREAK.LABEL === label) {
    delete BREAK.LABEL
    return
  }
  
  // Continue with a label shouldn't escape the labeled loop
  if (result === CONTINUE && CONTINUE.LABEL === label) {
    delete CONTINUE.LABEL
    // This shouldn't happen if loops handle it correctly
  }
  
  return result
}

export function IfStatement(node: estree.IfStatement, scope: Scope) {
  if (evaluate(node.test, scope)) {
    return evaluate(node.consequent, scope)
  } else {
    return evaluate(node.alternate, scope)
  }
}

export function SwitchStatement(node: estree.SwitchStatement, scope: Scope) {
  const discriminant = evaluate(node.discriminant, scope)
  let matched = false
  for (let i = 0; i < node.cases.length; i++) {
    const eachCase = node.cases[i]
    if (
      !matched
      && (
        !eachCase.test  // default
        || (evaluate(eachCase.test, scope)) === discriminant
      )
    ) {
      matched = true
    }
    if (matched) {
      const result = SwitchCase(eachCase, scope)
      if (result === BREAK) {
        break
      }
      if (result === CONTINUE || result === RETURN) {
        return result
      }
    }
  }
}

export function SwitchCase(node: estree.SwitchCase, scope: Scope) {
  for (let i = 0; i < node.consequent.length; i++) {
    const result = evaluate(node.consequent[i], scope)
    if (result === BREAK || result === CONTINUE || result === RETURN) {
      return result
    }
  }
}

export function ThrowStatement(node: estree.ThrowStatement, scope: Scope) {
  throw evaluate(node.argument, scope)
}

export function TryStatement(node: estree.TryStatement, scope: Scope) {
  try {
    return BlockStatement(node.block, scope)
  } catch (err) {
    if (node.handler) {
      const subScope = new Scope(scope)
      const param = node.handler.param
      if (param) {
        if (param.type === 'Identifier') {
          const name = param.name
          subScope.var(name, err)
        } else {
          pattern(param, scope, { feed: err })
        }
      }
      return CatchClause(node.handler, subScope)
    } else {
      throw err
    }
  } finally {
    if (node.finalizer) {
      const result = BlockStatement(node.finalizer, scope)
      if (result === BREAK || result === CONTINUE || result === RETURN) {
        return result
      }
    }
  }
}

export function CatchClause(node: estree.CatchClause, scope: Scope) {
  return BlockStatement(node.body, scope, { invasived: true })
}

export function WhileStatement(node: estree.WhileStatement, scope: Scope) {
  // Only check for label in immediate parent scope, not up the chain
  const myLabel = scope.hasOwn('__LABEL__') ? scope.find('__LABEL__').get() : undefined
  
  while (evaluate(node.test, scope)) {
    const result = evaluate(node.body, scope)
    if (result === BREAK) {
      if (BREAK.LABEL) {
        if (BREAK.LABEL === myLabel) {
          delete BREAK.LABEL
          break
        }
        return result
      }
      break
    } else if (result === CONTINUE) {
      if (CONTINUE.LABEL) {
        if (CONTINUE.LABEL === myLabel) {
          delete CONTINUE.LABEL
          continue
        }
        return result
      }
      continue
    } else if (result === RETURN) {
      return result
    }
  }
}

export function DoWhileStatement(node: estree.DoWhileStatement, scope: Scope) {
  // Only check for label in immediate parent scope, not up the chain
  const myLabel = scope.hasOwn('__LABEL__') ? scope.find('__LABEL__').get() : undefined
  
  do {
    const result = evaluate(node.body, scope)
    if (result === BREAK) {
      if (BREAK.LABEL) {
        if (BREAK.LABEL === myLabel) {
          delete BREAK.LABEL
          break
        }
        return result
      }
      break
    } else if (result === CONTINUE) {
      if (CONTINUE.LABEL) {
        if (CONTINUE.LABEL === myLabel) {
          delete CONTINUE.LABEL
          continue
        }
        return result
      }
      continue
    } else if (result === RETURN) {
      return result
    }
  } while (evaluate(node.test, scope))
}

export function ForStatement(node: estree.ForStatement, scope: Scope) {
  const forScope = new Scope(scope)
  
  // Only check for label in immediate parent scope, not up the chain
  const myLabel = scope.hasOwn('__LABEL__') ? scope.find('__LABEL__').get() : undefined
  
  for (
    evaluate(node.init, forScope);
    node.test ? (evaluate(node.test, forScope)) : true;
    evaluate(node.update, forScope)
  ) {
    const subScope = new Scope(forScope)
    let result: any
    if (node.body.type === 'BlockStatement') {
      result = BlockStatement(node.body, subScope, { invasived: true })
    } else {
      result = evaluate(node.body, subScope)
    }

    if (result === BREAK) {
      if (BREAK.LABEL) {
        // Check if the break is targeting this loop's label
        if (BREAK.LABEL === myLabel) {
          delete BREAK.LABEL
          break
        }
        // Otherwise pass it up
        return result
      }
      break
    } else if (result === CONTINUE) {
      if (CONTINUE.LABEL) {
        // Check if the continue is targeting this loop's label
        if (CONTINUE.LABEL === myLabel) {
          delete CONTINUE.LABEL
          continue
        }
        // Otherwise pass it up
        return result
      }
      continue
    } else if (result === RETURN) {
      return result
    }
  }
}

export function ForInStatement(node: estree.ForInStatement, scope: Scope) {
  // Only check for label in immediate parent scope, not up the chain
  const myLabel = scope.hasOwn('__LABEL__') ? scope.find('__LABEL__').get() : undefined
  
  for (const value in evaluate(node.right, scope)) {
    const result = ForXHandler(node, scope, { value })
    if (result === BREAK) {
      if (BREAK.LABEL) {
        if (BREAK.LABEL === myLabel) {
          delete BREAK.LABEL
          break
        }
        return result
      }
      break
    } else if (result === CONTINUE) {
      if (CONTINUE.LABEL) {
        if (CONTINUE.LABEL === myLabel) {
          delete CONTINUE.LABEL
          continue
        }
        return result
      }
      continue
    } else if (result === RETURN) {
      return result
    }
  }
}

export function ForOfStatement(node: estree.ForOfStatement, scope: Scope) {
  // Only check for label in immediate parent scope, not up the chain
  const myLabel = scope.hasOwn('__LABEL__') ? scope.find('__LABEL__').get() : undefined
  const right = evaluate(node.right, scope)
  
    for (const value of right) {
      const result = ForXHandler(node, scope, { value })
      if (result === BREAK) {
        if (BREAK.LABEL) {
          if (BREAK.LABEL === myLabel) {
            delete BREAK.LABEL
            break
          }
          return result
        }
        break
      } else if (result === CONTINUE) {
        if (CONTINUE.LABEL) {
          if (CONTINUE.LABEL === myLabel) {
            delete CONTINUE.LABEL
            continue
          }
          return result
        }
        continue
      } else if (result === RETURN) {
        return result
      }
    }
  
}
